import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/Navbar';
import api from '../services/api';

function NewApplication() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    companyName: '',
    sector: 'Manufacturing',
    revenue: 100,
    ebitda: 15,
    netProfit: 8,
    totalDebt: 40,
    netWorth: 60,
    gstTurnover: 95,
    capacityUtilization: 75,
    managementQuality: 7,
    siteVisitScore: 7
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await api.processApplication(formData);
      localStorage.setItem('results', JSON.stringify(response));
      navigate('/results');
    } catch (error) {
      alert('Error processing application: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="gradient-bg" style={{ minHeight: '100vh' }}>
      <Navbar />

      <div className="container">
        <div className="card" style={{ maxWidth: '900px', margin: '2rem auto' }}>
          <h1 className="title" style={{ fontSize: '2.5rem' }}>
            📋 New Credit Application
          </h1>
          <p style={{ textAlign: 'center', color: '#666', marginBottom: '2rem' }}>
            Enter company details to get instant credit analysis
          </p>

          <form onSubmit={handleSubmit}>
            {/* Company Information */}
            <h3 style={{ color: '#667eea', marginBottom: '1rem' }}>Company Information</h3>
            <div className="grid grid-2">
              <div>
                <label className="label">Company Name *</label>
                <input
                  type="text"
                  name="companyName"
                  className="input"
                  value={formData.companyName}
                  onChange={handleChange}
                  required
                />
              </div>
              <div>
                <label className="label">Sector *</label>
                <select
                  name="sector"
                  className="input"
                  value={formData.sector}
                  onChange={handleChange}
                >
                  <option>Manufacturing</option>
                  <option>Services</option>
                  <option>Trading</option>
                  <option>NBFC</option>
                  <option>IT/Software</option>
                </select>
              </div>
            </div>

            {/* Financial Data */}
            <h3 style={{ color: '#667eea', margin: '2rem 0 1rem' }}>Financial Data (₹ Crores)</h3>
            <div className="grid grid-3">
              <div>
                <label className="label">Revenue</label>
                <input
                  type="number"
                  name="revenue"
                  className="input"
                  value={formData.revenue}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label className="label">EBITDA</label>
                <input
                  type="number"
                  name="ebitda"
                  className="input"
                  value={formData.ebitda}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label className="label">Net Profit</label>
                <input
                  type="number"
                  name="netProfit"
                  className="input"
                  value={formData.netProfit}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label className="label">Total Debt</label>
                <input
                  type="number"
                  name="totalDebt"
                  className="input"
                  value={formData.totalDebt}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label className="label">Net Worth</label>
                <input
                  type="number"
                  name="netWorth"
                  className="input"
                  value={formData.netWorth}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label className="label">GST Turnover</label>
                <input
                  type="number"
                  name="gstTurnover"
                  className="input"
                  value={formData.gstTurnover}
                  onChange={handleChange}
                />
              </div>
            </div>

            {/* Primary Insights */}
            <h3 style={{ color: '#667eea', margin: '2rem 0 1rem' }}>Primary Insights</h3>
            <div className="grid grid-3">
              <div>
                <label className="label">Capacity Utilization (%)</label>
                <input
                  type="range"
                  name="capacityUtilization"
                  min="0"
                  max="100"
                  value={formData.capacityUtilization}
                  onChange={handleChange}
                  style={{ width: '100%' }}
                />
                <div style={{ textAlign: 'center', fontWeight: '600' }}>
                  {formData.capacityUtilization}%
                </div>
              </div>
              <div>
                <label className="label">Management Quality (1-10)</label>
                <input
                  type="range"
                  name="managementQuality"
                  min="1"
                  max="10"
                  value={formData.managementQuality}
                  onChange={handleChange}
                  style={{ width: '100%' }}
                />
                <div style={{ textAlign: 'center', fontWeight: '600' }}>
                  {formData.managementQuality}/10
                </div>
              </div>
              <div>
                <label className="label">Site Visit Score (1-10)</label>
                <input
                  type="range"
                  name="siteVisitScore"
                  min="1"
                  max="10"
                  value={formData.siteVisitScore}
                  onChange={handleChange}
                  style={{ width: '100%' }}
                />
                <div style={{ textAlign: 'center', fontWeight: '600' }}>
                  {formData.siteVisitScore}/10
                </div>
              </div>
            </div>

            {/* Submit Button */}
            <div style={{ textAlign: 'center', marginTop: '3rem' }}>
              {loading ? (
                <div className="spinner"></div>
              ) : (
                <button type="submit" className="btn">
                  🚀 Process Application
                </button>
              )}
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

export default NewApplication;
